import React, { useEffect, useMemo, useState } from "react";

const API_URL = process.env.REACT_APP_API_URL || "";
const API_BASE = API_URL.replace(/\/api\/?$/, "");

const toAttachmentUrl = (url) => {
  if (!url) return "";
  if (url.startsWith("http://") || url.startsWith("https://")) return url;
  return `${API_BASE}${url}`;
};

export default function RoomSettingsModal({
  open,
  activeRoom,
  roomUsers,
  currentUser,
  mediaItems,
  loadingMedia,
  onClose,
  onSaveRoom,
  onUploadAvatar,
  onDeleteRoom,
  onKickMember
}) {
  const [name, setName] = useState("");
  const [description, setDescription] = useState("");
  const [saving, setSaving] = useState(false);
  const [avatarUploading, setAvatarUploading] = useState(false);
  const creatorId = activeRoom?.createdBy?._id || activeRoom?.createdBy?.id || activeRoom?.createdBy;
  const isAdmin = useMemo(
    () => activeRoom?.admins?.some((admin) => (admin._id || admin.id) === currentUser?.id) || creatorId === currentUser?.id,
    [activeRoom, creatorId, currentUser]
  );

  useEffect(() => {
    if (!activeRoom) return;
    setName(activeRoom.name || "");
    setDescription(activeRoom.description || "");
  }, [activeRoom]);

  if (!open || !activeRoom) return null;

  const handleSave = async (event) => {
    event.preventDefault();
    if (!isAdmin) return;
    setSaving(true);
    try {
      await onSaveRoom(activeRoom._id, { name, description });
    } finally {
      setSaving(false);
    }
  };

  const handleAvatarChange = async (event) => {
    if (!isAdmin) return;
    const file = event.target.files?.[0];
    if (!file) return;
    setAvatarUploading(true);
    try {
      await onUploadAvatar(activeRoom._id, file);
    } finally {
      setAvatarUploading(false);
      event.target.value = "";
    }
  };

  const handleDelete = async () => {
    if (!isAdmin) return;
    if (!window.confirm("Delete this room for everyone?")) return;
    await onDeleteRoom(activeRoom._id);
    onClose();
  };

  return (
    <div className="modal-backdrop" role="dialog" aria-modal="true">
      <section className="modal-card room-settings-modal">
        <div className="modal-head">
          <h3>Room settings</h3>
          <button type="button" className="ghost-btn" onClick={onClose}>Close</button>
        </div>

        <div className="room-settings-section">
          <h4>Members ({roomUsers.length})</h4>
          <div className="room-settings-members">
            {roomUsers.map((member) => {
              const memberId = member.id || member._id;
              const canKick = isAdmin && memberId !== currentUser?.id && memberId !== creatorId;
              return (
                <div className="details-member-row" key={memberId}>
                  <span className={member.online ? "member-dot online" : "member-dot offline"} />
                  <span className="member-name">{member.username}</span>
                  {canKick ? <button type="button" className="member-kick member-kick-visible" onClick={() => onKickMember(activeRoom._id, memberId)}>Kick</button> : null}
                </div>
              );
            })}
          </div>
        </div>

        <div className="room-settings-section">
          <h4>Media ({mediaItems.length})</h4>
          {loadingMedia ? <p className="room-settings-muted">Loading images...</p> : null}
          {!loadingMedia && !mediaItems.length ? <p className="room-settings-muted">No images have been shared in this room yet.</p> : null}
          {!!mediaItems.length ? (
            <div className="room-media-grid">
              {mediaItems.map((media, index) => (
                <a key={`${media.url}-${index}`} href={toAttachmentUrl(media.url)} target="_blank" rel="noreferrer" className="room-media-item">
                  <img src={toAttachmentUrl(media.url)} alt={media.fileName || "Room image"} />
                </a>
              ))}
            </div>
          ) : null}
        </div>

        {isAdmin ? (
          <form className="room-settings-section room-form" onSubmit={handleSave}>
            <h4>Admin actions</h4>
            <label>
              Room name
              <input type="text" value={name} minLength={2} maxLength={40} onChange={(event) => setName(event.target.value)} required />
            </label>
            <label>
              Description
              <input type="text" value={description} maxLength={200} onChange={(event) => setDescription(event.target.value)} />
            </label>
            <label>
              Room profile picture
              <input type="file" accept="image/*" onChange={handleAvatarChange} disabled={avatarUploading} />
            </label>
            <div className="room-settings-actions">
              <button type="submit" className="primary-btn" disabled={saving}>{saving ? "Saving..." : "Save settings"}</button>
              <button type="button" className="danger-btn" onClick={handleDelete}>Delete room</button>
            </div>
          </form>
        ) : (
          <div className="room-settings-section">
            <h4>Permissions</h4>
            <p className="room-settings-muted">You can view members and room media. Admins can edit settings, kick members, and delete the room.</p>
          </div>
        )}
      </section>
    </div>
  );
}
